%[text] ## Creating IIR Filters
%[text] 
fs = single(8e3);
t = 0:1/fs:(1-1/fs);

fc_low  = fs/6;
fc_high = 2*fs/6; 

lp = load("lp.mat");
hp = load("hp.mat");
bp = load("bp.mat");

x = chirp(t,-fs/2,1-1/fs,fs/2);

y_lp = sosfilt(lp.SOS,x)*prod(lp.G);

figure %[output:66cbea58]
subplot(4,1,1) %[output:66cbea58]
plot(x) %[output:66cbea58]
title("") %[output:66cbea58]
subplot(4,1,2) %[output:66cbea58]
plot(abs(fft(x))) %[output:66cbea58]
xlim([0,fs/2]); %[output:66cbea58]
subplot(4,1,3) %[output:66cbea58]
plot(abs(fft(y_lp))) %[output:66cbea58]
xlim([0,fs/2]); %[output:66cbea58]
subplot(4,1,4) %[output:66cbea58]
plot(y_lp) %[output:66cbea58]

% Manual implementation

% Create an internal TDL corresponding to each SOS section
% For each x in: Loop through each SOS on TDL
% Try 1: multiplying by G within loop
% Try 2: Mult by G at end


% TDL -> n=0,n=-1, n=-2

tdl = zeros(3,1+size(lp.SOS, 1));
y_lp_man = zeros(1,length(x));

for xit = 1:length(x)
    tdl(1,1) = x(xit);

    for sosit = 1:size(lp.SOS, 1)
        % x is tdl(:,sosit - 1), y is tdl(:,sosit)
        % -> x[n] = tdl(1,sosit-1), y[n-1] = tdl(2, sosit)
        sos = lp.SOS(sosit,:);
        x_sos = tdl(:,sosit);
        y_sos = tdl(2:end,sosit+1);

        % each sos filter is one row in filt.SOS
        % H -> [b0, b1, b2, 1, a1, a2]
        % difference equation is therefore:
        % y[n] = b0x[n] + b1x[n-1] + b2x[n-2] -a1y[n-1] - a2y[n-2]
        tdl(1,sosit+1) = sum(x_sos'.*sos(1:3))- sum(y_sos'.*sos(5:end));        
    end
    y_lp_man(xit) = tdl(1,end);
    tdl = [ zeros(1,1+size(lp.SOS, 1))
            tdl(1:(end-1), :)
            ];
end

y_lp_man = y_lp_man*prod(lp.G);


figure %[output:7356aef9]
subplot(6,1,1) %[output:7356aef9]
plot(x) %[output:7356aef9]
title("") %[output:7356aef9]
subplot(6,1,2) %[output:7356aef9]
plot(abs(fft(x))) %[output:7356aef9]
xlim([0,fs/2]); %[output:7356aef9]
subplot(6,1,3) %[output:7356aef9]
plot(abs(fft(y_lp))) %[output:7356aef9]
xlim([0,fs/2]); %[output:7356aef9]
subplot(6,1,4) %[output:7356aef9]
plot(y_lp) %[output:7356aef9]
subplot(6,1,5) %[output:7356aef9]
plot(abs(fft(y_lp_man))) %[output:7356aef9]
xlim([0,fs/2]); %[output:7356aef9]
subplot(6,1,6) %[output:7356aef9]
plot(y_lp_man) %[output:7356aef9]
y_man_mse = mean( (y_lp - y_lp_man).^2 ) %[output:7ab9258b]




function save_sos(b_fir,a_fir,filename,prefix)
    fid = fopen(filename,'w');
    
    fprintf(fid,['#pragma once' char([13 10])]);
    fwrite(fid,char([13 10]),'uchar');
    
    %% FIR FILTER
    %% B
    fprintf(fid,['#define %s_N_FIR_B %d' char([13 10])], prefix,length(b_fir));
    fwrite(fid,char([13 10]),'uchar');
    
    fwrite(fid,'float '+prefix+'_b_fir[] = { ','uchar');
    for ct = 1:length(b_fir)-1
        fprintf(fid,'%.7ff, ', single(b_fir(ct)));
    end
    fprintf(fid,'%.7ff', single(b_fir(end)));
    fwrite(fid,[' };' char([13 10])],'uchar');
    fwrite(fid,char([13 10]),'uchar');

    %% A
    fprintf(fid,['#define %s_N_FIR_A %d' char([13 10])], prefix,length(a_fir));
    fwrite(fid,char([13 10]),'uchar');
    fwrite(fid,'float '+prefix+'_a_fir[] = { ','uchar');
    for ct = 1:length(a_fir)-1
        fprintf(fid,'%.7ff, ', single(a_fir(ct)));
    end
    fprintf(fid,'%.7ff', single(a_fir(end)));
    fwrite(fid,[' };' char([13 10])],'uchar');
    fwrite(fid,char([13 10]),'uchar');
    
    
    fclose(fid);
end

save_filter(h1,1,"data_1.h","Filter_1")
save_filter(h2,1,"data_2.h","Filter_2")

